import { iterate } from "/iterate.module.static.js";

function fixCusor(value) {
    if (value) {
        document.body.style.cursor = "url('res/cursors/hand-pointer.png'), auto";
    }
    if (!value) {
        document.body.style.cursor = "url('res/cursors/plus-outline.png'), auto";
    }
}

let cards = document.querySelectorAll('.card');
let h1 = document.querySelectorAll('h1');
let h2 = document.querySelectorAll('h2');

document.body.addEventListener('mouseenter', function() {fixCusor(true)});

document.body.addEventListener('mouseleave', function() {fixCusor(false)});

iterate(cards, h1, h2)